import BasePlugin from"../base-plugin.js";import WaveSurfer from"../wavesurfer.js";const defaultOptions={height:50,overlayColor:"rgba(100, 100, 100, 0.1)"};class MinimapPlugin extends BasePlugin{options;minimapWrapper;miniWavesurfer=null;overlay;constructor(i){super(i),this.options=Object.assign({},defaultOptions,i),this.minimapWrapper=this.initMinimapWrapper(),this.overlay=this.initOverlay()}static create(i){return new MinimapPlugin(i)}init(i){if(super.init(i),!this.wavesurfer)throw Error("WaveSurfer is not initialized");this.container?.insertAdjacentElement("afterend",this.minimapWrapper),this.subscriptions.push(this.wavesurfer.on("decode",()=>{this.initMinimap()}))}initMinimapWrapper(){const i=document.createElement("div");return i.style.position="relative",i}initOverlay(){const i=document.createElement("div");return i.setAttribute("style","position: absolute; z-index: 2; left: 0; top: 0; bottom: 0;"),i.style.backgroundColor=this.options.overlayColor,this.minimapWrapper.appendChild(i),i}initMinimap(){if(this.wavesurfer&&this.wrapper){const e=this.wavesurfer.getDecodedData();var i=this.wavesurfer.getMediaElement();if(e&&i){this.miniWavesurfer=WaveSurfer.create({...this.options,container:this.minimapWrapper,minPxPerSec:1,fillParent:!0,media:i,url:i.src,peaks:[e.getChannelData(0)],duration:e.duration});const t=Math.round(this.minimapWrapper.clientWidth/this.wrapper.clientWidth*100);this.overlay.style.width=t+"%",this.wavesurfer.on("timeupdate",({currentTime:i})=>{i=Math.max(0,Math.min(i/e.duration*100-t/2,100-t)).toFixed(2);this.overlay.style.left=i+"%"})}}}destroy(){this.miniWavesurfer?.destroy(),this.minimapWrapper.remove(),super.destroy()}}export default MinimapPlugin;